                                <p className="text-gray-500 text-xs data-readout">
                                    JPG, PNG, GIF, WebP, MP4, WebM, MOV
                                </p>
                                <input
                                    ref={fileInputRef}
                                    type="file"
                                    multiple
                                    accept="image/*,video/*"
                                    className="hidden"
                                    onChange={(e) => {
