"use client";

import { useEffect, useState, useRef, useCallback } from "react";
import { useSearchParams } from "next/navigation";
import { Talent, getTalents, saveTalent, deleteTalent, generateId, slugify, uploadMediaFile } from "@/lib/dataStore";
import { Plus, Edit, Trash2, X, Save, Microscope, Upload, ImageIcon, Link } from "lucide-react";

function TalentForm({ talent, onSave, onCancel }: { talent?: Talent; onSave: () => void; onCancel: () => void }) {
    const [form, setForm] = useState({
        name: talent?.name || "",
        role: talent?.role || "",
        image: talent?.image || "",
        code: talent?.code || "",
        bio: talent?.bio || "",
    });
    const [imageMode, setImageMode] = useState<"upload" | "url">(talent?.image ? "url" : "upload");
    const [uploading, setUploading] = useState(false);
    const [uploadProgress, setUploadProgress] = useState(0);
    const [dragOver, setDragOver] = useState(false);
    const [errorMsg, setErrorMsg] = useState("");
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleFileUpload = useCallback(async (file: File) => {
        if (!file.type.startsWith("image/")) {
            alert("Solo file immagine sono supportati.");
            return;
        }
        setUploading(true);
        setUploadProgress(10);
        const interval = setInterval(() => {
            setUploadProgress((p) => Math.min(p + 15, 90));
        }, 200);

        const url = await uploadMediaFile(file, "talents");

        clearInterval(interval);
        setUploadProgress(100);

        if (url) {
            setForm((prev) => ({ ...prev, image: url }));
            setTimeout(() => {
                setUploading(false);
                setUploadProgress(0);
            }, 500);
        } else {
            alert("Errore durante il caricamento. Riprova.");
            setUploading(false);
            setUploadProgress(0);
        }
    }, []);

    const handleDrop = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setDragOver(false);
        const file = e.dataTransfer.files[0];
        if (file) handleFileUpload(file);
    }, [handleFileUpload]);

    const handleDragOver = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setDragOver(true);
    }, []);

    const handleDragLeave = useCallback(() => {
        setDragOver(false);
    }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setErrorMsg("");
        if (!form.image) {
            setErrorMsg("Inserisci o carica un'immagine.");
            return;
        }
        try {
            await saveTalent({
                id: talent?.id || slugify(form.name),
                ...form,
                code: form.code || `RES-${generateId().slice(0, 3).toUpperCase()}`,
            });
            onSave();
        } catch (err: any) {
            setErrorMsg(err.message || "Impossibile salvare il ricercatore.");
        }
    };

    const inputClass = "w-full bg-lab-dark/80 border border-green/15 px-4 py-2.5 text-rama-text text-sm data-readout placeholder:text-gray-600 focus:outline-none focus:border-green/40 transition-all duration-300";
    const labelClass = "data-readout text-[10px] text-amber/40 tracking-[0.2em] uppercase block mb-1.5";

    return (
        <form onSubmit={handleSubmit} className="space-y-4 max-w-2xl">
            <div className="flex items-center justify-between border-b border-green/10 pb-3 mb-4">
                <h3 className="text-lg font-bold text-rama-text">{talent ? "Modifica Artista" : "Nuovo Artista"}</h3>
                <button type="button" onClick={onCancel} className="text-gray-500 hover:text-rama-text cursor-pointer"><X size={20} /></button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                    <label className={labelClass}>Nome</label>
                    <input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} required placeholder="Chef Rubio" className={inputClass} />
                </div>
                <div>
                    <label className={labelClass}>Ruolo</label>
                    <input value={form.role} onChange={(e) => setForm({ ...form, role: e.target.value })} required placeholder="Direttore Culinario" className={inputClass} />
                </div>
                <div>
                    <label className={labelClass}>Codice</label>
                    <input value={form.code} onChange={(e) => setForm({ ...form, code: e.target.value })} placeholder="RES-001" className={inputClass} />
                </div>
            </div>

            {/* Image section */}
            <div>
                <div className="flex items-center gap-3 mb-2">
                    <label className={`${labelClass} mb-0`}>Foto Artista</label>
                    <div className="flex gap-1 ml-auto">
                        <button
                            type="button"
                            onClick={() => setImageMode("upload")}
                            className={`flex items-center gap-1 px-2.5 py-1 text-[10px] data-readout tracking-wider uppercase border transition-all cursor-pointer ${imageMode === "upload"
                                    ? "border-cyan/40 bg-cyan/10 text-cyan"
                                    : "border-green/10 text-gray-500 hover:text-gray-300"
                                }`}
                        >
                            <Upload size={10} /> Carica
                        </button>
                        <button
                            type="button"
                            onClick={() => setImageMode("url")}
                            className={`flex items-center gap-1 px-2.5 py-1 text-[10px] data-readout tracking-wider uppercase border transition-all cursor-pointer ${imageMode === "url"
                                    ? "border-cyan/40 bg-cyan/10 text-cyan"
                                    : "border-green/10 text-gray-500 hover:text-gray-300"
                                }`}
                        >
                            <Link size={10} /> URL
                        </button>
                    </div>
                </div>

                {imageMode === "upload" ? (
                    <div
                        onDrop={handleDrop}
                        onDragOver={handleDragOver}
                        onDragLeave={handleDragLeave}
                        onClick={() => !uploading && fileInputRef.current?.click()}
                        className={`relative border-2 border-dashed p-6 text-center transition-all duration-300 cursor-pointer ${dragOver
                                ? "border-cyan/60 bg-cyan/10"
                                : uploading
                                    ? "border-amber/30 bg-amber/5"
                                    : "border-green/15 hover:border-green/30 bg-lab-dark/50"
                            }`}
                    >
                        <input
                            ref={fileInputRef}
                            type="file"
                            accept="image/*"
                            className="hidden"
                            onChange={(e) => {
                                const file = e.target.files?.[0];
                                if (file) handleFileUpload(file);
                                e.target.value = "";
                            }}
                        />

                        {uploading ? (
                            <div className="space-y-3">
                                <div className="w-full h-1.5 bg-lab-dark/80 overflow-hidden">
                                    <div
                                        className="h-full bg-gradient-to-r from-cyan to-green transition-all duration-300"
                                        style={{ width: `${uploadProgress}%` }}
                                    />
                                </div>
                                <p className="data-readout text-[10px] text-amber/60 tracking-wider">
                                    CARICAMENTO IN CORSO... {uploadProgress}%
                                </p>
                            </div>
                        ) : (
                            <div className="space-y-2">
                                <ImageIcon size={28} className="mx-auto text-green/30" />
                                <p className="data-readout text-xs text-gray-400">
                                    Trascina una foto qui o <span className="text-cyan underline">sfoglia</span>
                                </p>
                                <p className="data-readout text-[9px] text-gray-600 tracking-wider">
                                    JPG, PNG, WEBP
                                </p>
                            </div>
                        )}
                    </div>
                ) : (
                    <input
                        value={form.image}
                        onChange={(e) => setForm({ ...form, image: e.target.value })}
                        placeholder="https://..."
                        className={inputClass}
                    />
                )}
            </div>

            <div>
                <label className={labelClass}>Biografia</label>
                <textarea value={form.bio} onChange={(e) => setForm({ ...form, bio: e.target.value })} rows={3} placeholder="Breve biografia..." className={`${inputClass} resize-none`} />
            </div>

            {form.image && (
                <div className="border border-amber/10 p-2">
                    <div className="flex items-center justify-between mb-1.5">
                        <span className="data-readout text-[9px] text-gray-muted tracking-wider">ANTEPRIMA</span>
                        {form.image && (
                            <button
                                type="button"
                                onClick={() => setForm({ ...form, image: "" })}
                                className="data-readout text-[9px] text-red/50 hover:text-red tracking-wider flex items-center gap-1 cursor-pointer"
                            >
                                <X size={8} /> Rimuovi
                            </button>
                        )}
                    </div>
                    <img src={form.image} alt="Preview" className="w-32 h-40 object-cover opacity-80" />
                </div>
            )}

            {errorMsg && (
                <div className="bg-red/10 border border-red/40 text-red text-sm px-4 py-3 data-readout">
                    ⚠ ERRORE: {errorMsg}
                </div>
            )}

            <div className="flex gap-3 pt-2">
                <button type="submit" disabled={uploading} className="flex-1 py-3 border border-amber/40 bg-amber/10 text-amber text-sm font-bold uppercase tracking-wider data-readout hover:bg-amber/20 transition-all flex items-center justify-center gap-2 cursor-pointer disabled:opacity-40 disabled:cursor-not-allowed">
                    <Save size={14} /> Salva Artista
                </button>
                <button type="button" onClick={onCancel} className="px-6 py-3 border border-gray-700 text-gray-400 text-sm data-readout uppercase tracking-wider hover:text-rama-text transition-colors cursor-pointer">
                    Annulla
                </button>
            </div>
        </form>
    );
}

export default function AdminTalentsPage() {
    const searchParams = useSearchParams();
    const [talents, setTalents] = useState<Talent[]>([]);
    const [editing, setEditing] = useState<Talent | null>(null);
    const [creating, setCreating] = useState(false);

    const load = () => { getTalents().then(setTalents); };

    useEffect(() => {
        load();
        if (searchParams.get("action") === "new") setCreating(true);
    }, [searchParams]);

    const handleDelete = async (id: string) => {
        if (confirm("Eliminare questo artista?")) {
            await deleteTalent(id);
            load();
        }
    };

    if (creating || editing) {
        return (
            <TalentForm
                talent={editing || undefined}
                onSave={() => { setCreating(false); setEditing(null); load(); }}
                onCancel={() => { setCreating(false); setEditing(null); }}
            />
        );
    }

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <span className="data-readout text-[10px] text-green/40 tracking-[0.3em] uppercase">TAL // Team Artisti</span>
                    <h1 className="text-3xl font-bold text-rama-text mt-1">Artisti</h1>
                </div>
                <button onClick={() => setCreating(true)} className="flex items-center gap-2 px-5 py-2.5 border border-amber/40 bg-amber/10 text-amber text-xs font-bold uppercase tracking-wider data-readout hover:bg-amber/20 transition-all cursor-pointer">
                    <Plus size={14} /> Nuovo Artista
                </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {talents.map((talent) => (
                    <div key={talent.id} className="border border-green/10 bg-lab-card/30 overflow-hidden group hover:border-amber/20 transition-all duration-300">
                        <div className="h-48 overflow-hidden relative">
                            <img src={talent.image} alt={talent.name} className="w-full h-full object-cover" />
                            <div className="absolute inset-0 bg-gradient-to-t from-lab-dark to-transparent opacity-60" />
                            <div className="absolute top-2 right-2">
                                <span className="data-readout text-[9px] text-green/40 tracking-wider flex items-center gap-1 bg-lab-dark/80 px-2 py-0.5">
                                    <Microscope size={8} /> {talent.code}
                                </span>
                            </div>
                        </div>
                        <div className="p-4">
                            <span className="data-readout text-[10px] text-amber/50 tracking-wider uppercase">{talent.role}</span>
                            <h3 className="text-lg font-bold text-rama-text mt-1">{talent.name}</h3>
                            {talent.bio && <p className="text-gray-500 text-xs mt-1 line-clamp-2">{talent.bio}</p>}
                            <div className="flex items-center gap-2 mt-3 opacity-50 group-hover:opacity-100 transition-opacity">
                                <button onClick={() => setEditing(talent)} className="flex items-center gap-1 text-cyan text-[10px] data-readout hover:text-cyan/80 cursor-pointer">
                                    <Edit size={12} /> Modifica
                                </button>
                                <button onClick={() => handleDelete(talent.id)} className="flex items-center gap-1 text-red/50 text-[10px] data-readout hover:text-red cursor-pointer">
                                    <Trash2 size={12} /> Elimina
                                </button>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            {talents.length === 0 && (
                <div className="text-center py-12 text-gray-500 data-readout text-sm">
                    Nessun artista. Aggiungi il primo!
                </div>
            )}
        </div>
    );
}

"use client";

import { useState, useMemo, useRef } from "react";
import { useSearchParams } from "next/navigation";
import { ArrowLeft, CreditCard, Lock, CheckCircle, ChevronRight, ChevronLeft, ShieldCheck, Mail, Phone, User, Calendar, Info } from "lucide-react";
import Link from "next/link";
import { useGSAP } from "@/hooks/useGSAP";
import { gsap } from "gsap";

export default function CheckoutForm() {
    const searchParams = useSearchParams();
    const eventId = searchParams.get("eventId");

    const event = {
        id: "1",
        title: eventId === "il-palqo" ? "Il PalQo" : eventId === "a-cena-con-il-bugiardo" ? "A Cena Con Il Bugiardo" : eventId === "the-golden-voice" ? "The Golden Voice" : "Cena Con Delitto",
        price: 85,
        location: "Sala dei Cavalieri",
    };

    const [step, setStep] = useState(1);
    const formAreaRef = useRef<HTMLDivElement>(null);

    // Step 1 State
    const [quantity, setQuantity] = useState(2);
    const [selectedDate, setSelectedDate] = useState<Date | null>(null);

    // Step 2 State
    const [guest, setGuest] = useState({ name: "", surname: "", email: "", phone: "" });

    // Step 3 State
    const [premium, setPremium] = useState({ allergies: "", occasion: "" });
    const [loading, setLoading] = useState(false);

    // Validations
    const isEmailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(guest.email);
    const isPhoneValid = guest.phone.replace(/[^0-9]/g, '').length >= 9;
    const isStep1Valid = selectedDate !== null && quantity > 0;
    const isStep2Valid = guest.name.length > 1 && guest.surname.length > 1 && isEmailValid && isPhoneValid;

    // Calendar Logic
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const [currentMonth, setCurrentMonth] = useState(new Date(today.getFullYear(), today.getMonth(), 1));

    const calendarDates = useMemo(() => {
        const year = currentMonth.getFullYear();
        const month = currentMonth.getMonth();
        const firstDay = new Date(year, month, 1).getDay();
        const daysInMonth = new Date(year, month + 1, 0).getDate();

        const dates = [];
        // Pad empty days at start
        const emptyDays = firstDay === 0 ? 6 : firstDay - 1; // Assuming Monday is first
        for (let i = 0; i < emptyDays; i++) dates.push(null);

        for (let i = 1; i <= daysInMonth; i++) {
            const d = new Date(year, month, i);
            const isPast = d < today;
            const isSoldOut = !isPast && (d.getDate() % 5 === 0 || d.getDate() % 8 === 0);
            dates.push({ date: d, isPast, isSoldOut });
        }
        return dates;
    }, [currentMonth, today]);

    const handleNextMonth = () => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 1));
    const handlePrevMonth = () => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1, 1));

    useGSAP(() => {
        if (formAreaRef.current) {
            gsap.fromTo(formAreaRef.current.children, 
                { opacity: 0, x: 20 },
                { opacity: 1, x: 0, duration: 0.4, ease: "power2.out", overwrite: true }
            );
        }
    }, { dependencies: [step], scope: formAreaRef });

    const handlePayment = async () => {
        setLoading(true);
        try {
            const response = await fetch("/api/checkout", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    eventId: event.id,
                    eventTitle: event.title,
                    quantity,
                    selectedDate,
                    guest,
                    premium
                })
            });
            const data = await response.json();
            if (data.url) {
                window.location.href = data.url;
            } else {
                throw new Error(data.error || "Errore durante la creazione della sessione");
            }
        } catch (error) {
            console.error("Payment error:", error);
            alert("Si è verificato un errore di connessione con il sistema di pagamento. Riprova.");
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-transparent pt-24 pb-32 px-4 sm:px-6">
            <div className="max-w-4xl mx-auto">
                <div className="flex justify-between items-center mb-12">
                    <Link href={`/events/${eventId || '1'}`} className="inline-flex items-center gap-2 text-gray-400 hover:text-white transition-colors">
                        <ArrowLeft size={16} />
                        Torna all&apos;evento
                    </Link>

                    {/* Progress Indicator */}
                    <div className="flex gap-4 items-center">
                        {[1, 2, 3].map(i => (
                            <div key={i} className="flex items-center gap-2">
                                <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm transition-colors ${step === i ? 'bg-gold text-black' : step > i ? 'bg-green-500/20 text-green-400' : 'bg-white/10 text-gray-500'}`}>
                                    {step > i ? <CheckCircle size={16} /> : i}
                                </div>
                                {i < 3 && <div className={`w-8 h-[2px] ${step > i ? 'bg-green-500/50' : 'bg-white/10'}`} />}
                            </div>
                        ))}
                    </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 lg:gap-12">

                    {/* Left: Form Area */}
                    <div ref={formAreaRef} className="lg:col-span-8 bg-white/[0.02] border border-white/10 rounded-2xl p-6 sm:p-10 shadow-2xl relative overflow-hidden backdrop-blur-sm min-h-[500px]">
                        {/* STEP 1: L'Esperienza */}
                        {step === 1 && (
                            <div key="step1" className="space-y-8">
                                <div className="space-y-2">
                                    <h2 className="text-3xl font-bold font-mohave uppercase tracking-tighter text-white">L&apos;Esperienza</h2>
                                    <p className="text-gray-400 text-sm">Seleziona la data e il numero di partecipanti per {event.title}.</p>
                                </div>

                                {/* DatePicker */}
                                <div className="bg-white/5 border border-white/10 rounded-xl p-6">
                                    <div className="flex justify-between items-center mb-6">
                                        <h3 className="text-lg font-bold text-white flex items-center gap-2 text-center">
                                            <Calendar size={18} className="text-gold text-center" /> Data dell&apos;Evento
                                        </h3>
                                        <div className="flex items-center gap-4 text-white">
                                            <button onClick={handlePrevMonth} className="hover:text-gold transition-colors"><ChevronLeft size={20} /></button>
                                            <span className="font-bold uppercase tracking-widest text-sm text-gold text-center">
                                                {currentMonth.toLocaleString('it-IT', { month: 'long', year: 'numeric' })}
                                            </span>
                                            <button onClick={handleNextMonth} className="hover:text-gold transition-colors"><ChevronRight size={20} /></button>
                                        </div>
                                    </div>

                                    <div className="grid grid-cols-7 gap-1 sm:gap-2 text-center text-xs mb-2 text-gray-500 font-medium">
                                        {['Lun', 'Mar', 'Mer', 'Gio', 'Ven', 'Sab', 'Dom'].map(d => <div key={d} className="text-center">{d}</div>)}
                                    </div>

                                    <div className="grid grid-cols-7 gap-1 sm:gap-2">
                                        {calendarDates.map((item, idx) => {
                                            if (!item) return <div key={idx} className="aspect-square" />;
                                            const { date, isPast, isSoldOut } = item;
                                            const isSelected = selectedDate?.getTime() === date.getTime();

                                            return (
                                                <button
                                                    key={idx}
                                                    disabled={isPast || isSoldOut}
                                                    onClick={() => setSelectedDate(date)}
                                                    className={`aspect-square rounded-lg flex flex-col items-center justify-center transition-all disabled:cursor-not-allowed ${
                                                        isSelected ? 'bg-gold text-black border-gold shadow-[0_0_15px_rgba(200,164,78,0.3)]' :
                                                        isSoldOut ? 'bg-red-500/10 text-red-400 border border-red-500/20' :
                                                        isPast ? 'text-gray-600 opacity-50' : 'bg-white/5 text-white hover:bg-white/15 border border-white/10'
                                                    }`}
                                                >
                                                    <span className="text-lg font-bold block text-center">{date.getDate()}</span>
                                                    {isSoldOut && <span className="text-[9px] uppercase tracking-tighter opacity-80 leading-none text-center">Sold Out</span>}
                                                </button>
                                            );
                                        })}
                                    </div>
                                </div>

                                {/* Tickets Selection */}
                                <div className="bg-white/5 border border-white/10 rounded-xl p-6 flex items-center justify-between">
                                    <div>
                                        <h3 className="text-lg font-bold text-white mb-1">Ospiti</h3>
                                        <p className="text-gray-400 text-sm">Numero di persone al tavolo</p>
                                    </div>
                                    <div className="flex items-center gap-4 bg-black/50 rounded-lg p-2 border border-white/20">
                                        <button onClick={() => setQuantity(Math.max(1, quantity - 1))} className="w-10 h-10 flex items-center justify-center text-white hover:bg-white/10 rounded-md transition-colors text-xl font-bold bg-white/5">-</button>
                                        <span className="text-white font-bold w-6 text-center text-xl">{quantity}</span>
                                        <button onClick={() => setQuantity(quantity + 1)} className="w-10 h-10 flex items-center justify-center text-white hover:bg-white/10 rounded-md transition-colors text-xl font-bold bg-white/5">+</button>
                                    </div>
                                </div>

                                <button 
                                    onClick={() => setStep(2)} 
                                    disabled={!isStep1Valid}
                                    className="w-full bg-gold text-black font-bold uppercase tracking-widest py-4 rounded-xl hover:bg-white transition-all shadow-lg mt-4 disabled:opacity-50 disabled:cursor-not-allowed flex justify-center items-center gap-2"
                                >
                                    Continua all&apos;Ospite <ChevronRight size={18} />
                                </button>
                            </div>
                        )}

                        {/* STEP 2: L'Ospite */}
                        {step === 2 && (
                            <div key="step2" className="space-y-8">
                                <div className="space-y-2">
                                    <div onClick={() => setStep(1)} className="text-xs text-gold uppercase tracking-widest cursor-pointer hover:text-white flex items-center gap-1 mb-2"><ChevronLeft size={12}/> Torna a Data e Posti</div>
                                    <h2 className="text-3xl font-bold font-mohave uppercase tracking-tighter text-white">L&apos;Ospite</h2>
                                    <p className="text-gray-400 text-sm">I tuoi dettagli per confermare la prenotazione.</p>
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div className="space-y-2 relative">
                                        <label className="text-xs font-bold uppercase tracking-widest text-gray-400 flex items-center gap-2"><User size={14}/> Nome</label>
                                        <input type="text" value={guest.name} onChange={e => setGuest({...guest, name: e.target.value})} placeholder="Mario" className="w-full bg-black/30 border border-white/10 rounded-xl px-4 py-3.5 text-white focus:border-gold focus:ring-1 focus:ring-gold outline-none transition-all" />
                                    </div>
                                    <div className="space-y-2 relative">
                                        <label className="text-xs font-bold uppercase tracking-widest text-gray-400">Cognome</label>
                                        <input type="text" value={guest.surname} onChange={e => setGuest({...guest, surname: e.target.value})} placeholder="Rossi" className="w-full bg-black/30 border border-white/10 rounded-xl px-4 py-3.5 text-white focus:border-gold focus:ring-1 focus:ring-gold outline-none transition-all" />
                                    </div>

                                    <div className="space-y-2 relative">
                                        <label className="text-xs font-bold uppercase tracking-widest text-gray-400 flex items-center gap-2"><Mail size={14}/> Indirizzo Email</label>
                                        <div className="relative">
                                            <input type="email" value={guest.email} onChange={e => setGuest({...guest, email: e.target.value})} placeholder="mario.rossi@email.com" className={`w-full bg-black/30 border ${guest.email.length>0 && isEmailValid ? 'border-green-500/50' : 'border-white/10'} rounded-xl px-4 py-3.5 text-white focus:border-gold outline-none transition-all pr-12`} />
                                            {isEmailValid && <CheckCircle className="absolute right-4 top-1/2 -translate-y-1/2 text-green-500 w-5 h-5 flex items-center justify-center" />}
                                        </div>
                                    </div>

                                    <div className="space-y-2 relative">
                                        <label className="text-xs font-bold uppercase tracking-widest text-gray-400 flex items-center gap-2"><Phone size={14}/> Cellulare</label>
                                        <div className="relative">
                                            <input type="tel" value={guest.phone} onChange={e => setGuest({...guest, phone: e.target.value})} placeholder="+39 333 1234567" className={`w-full bg-black/30 border ${guest.phone.length>0 && isPhoneValid ? 'border-green-500/50' : 'border-white/10'} rounded-xl px-4 py-3.5 text-white focus:border-gold outline-none transition-all pr-12`} />
                                            {isPhoneValid && <CheckCircle className="absolute right-4 top-1/2 -translate-y-1/2 text-green-500 w-5 h-5 flex items-center justify-center" />}
                                        </div>
                                        <p className="text-[11px] text-gray-500 flex items-center gap-1.5 mt-1 border border-white/5 bg-white/5 p-2 rounded-lg"><Info size={12} className="text-gold flex-shrink-0" /> Lo useremo solo in caso di comunicazioni urgenti sul tuo tavolo.</p>
                                    </div>
                                </div>

                                <button 
                                    onClick={() => setStep(3)} 
                                    disabled={!isStep2Valid}
                                    className="w-full bg-gold text-black font-bold uppercase tracking-widest py-4 rounded-xl hover:bg-white transition-all shadow-lg mt-8 disabled:opacity-50 disabled:cursor-not-allowed flex justify-center items-center gap-2"
                                >
                                    Continua ai Dettagli Premium <ChevronRight size={18} />
                                </button>
                            </div>
                        )}

                        {/* STEP 3: Il Tocco Premium & Pagamento */}
                        {step === 3 && (
                            <div key="step3" className="space-y-8">
                                <div className="space-y-2">
                                    <div onClick={() => setStep(2)} className="text-xs text-gold uppercase tracking-widest cursor-pointer hover:text-white flex items-center gap-1 mb-2"><ChevronLeft size={12}/> Torna ai Dati Ospite</div>
                                    <h2 className="text-3xl font-bold font-mohave uppercase tracking-tighter text-white flex items-center gap-3">
                                        Il Tocco Premium <span className="px-2 py-0.5 bg-gold/20 text-gold text-xs rounded-full border border-gold/30">VIP</span>
                                    </h2>
                                    <p className="text-gray-400 text-sm">Aiutaci a farti vivere una serata magica, curando ogni tuo dettaglio.</p>
                                </div>

                                <div className="space-y-6 bg-white/5 border border-white/10 rounded-xl p-6">
                                    <div className="space-y-2">
                                        <label className="text-xs font-bold uppercase tracking-widest text-gray-400 uppercase">Allergie o Intolleranze</label>
                                        <textarea 
                                            value={premium.allergies} onChange={e => setPremium({...premium, allergies: e.target.value})}
                                            placeholder="Non esitare ad avvisarci di celiachia, intolleranze al lattosio o altro. Il nostro Chef creerà un'esperienza perfetta per te." 
                                            className="w-full bg-black/30 border border-white/10 rounded-xl px-4 py-3 text-white focus:border-gold outline-none h-24 transition-all resize-none text-sm"
                                        />
                                    </div>

                                    <div className="space-y-2">
                                        <label className="text-xs font-bold uppercase tracking-widest text-gray-400 uppercase">Occasione Speciale</label>
                                        <select 
                                            value={premium.occasion} onChange={e => setPremium({...premium, occasion: e.target.value})}
                                            className="w-full bg-black/30 border border-white/10 rounded-xl px-4 py-3.5 text-white focus:border-gold outline-none appearance-none cursor-pointer"
                                        >
                                            <option value="" className="bg-black">Un semplice evento esclusivo</option>
                                            <option value="compleanno" className="bg-black">Festeggio il Compleanno</option>
                                            <option value="anniversario" className="bg-black">Anniversario Romantico</option>
                                            <option value="azziendale" className="bg-black">Evento Aziendale / Team</option>
                                        </select>
                                    </div>
                                </div>

                                {/* Caparra & Checkout CTA */}
                                <div className="bg-gradient-to-br from-gold/10 to-red/10 border border-gold/30 rounded-xl p-6 relative overflow-hidden">
                                    {/* Security Banner Ribbon */}
                                    <div className="absolute top-0 right-0 bg-gold text-black text-[10px] font-bold uppercase tracking-widest px-8 py-1 transform translate-x-12 translate-y-4 rotate-45 shadow-lg">Secure</div>

                                    <div className="flex flex-col gap-4 mb-6 relative z-10">
                                        <h3 className="font-bold text-white text-lg">Conferma la Prenotazione</h3>
                                        <p className="text-sm text-gray-400">Per garantire il tavolo esclusivo, richiediamo una piccola caparra rimborsabile di <strong className="text-white">€20.00 a persona</strong>.</p>

                                        <div className="flex items-center justify-between border-y border-white/10 py-4 my-2">
                                            <span className="text-gray-300">Caparra totale ({quantity} ospiti)</span>
                                            <span className="text-3xl font-bold text-white underline decoration-gold underline-offset-4">€ {quantity * 20}.00</span>
                                        </div>
                                    </div>

                                    <button
                                        onClick={handlePayment}
                                        disabled={loading}
                                        className="w-full bg-gold text-black font-bold uppercase tracking-widest py-4 rounded-xl hover:bg-white transition-all shadow-lg flex items-center justify-center gap-3 relative z-10 group"
                                    >
                                        {loading ? "Elaborazione in Sicurezza..." : (
                                            <>
                                                <Lock size={18} className="group-hover:scale-110 transition-transform" />
                                                Riserva il mio Tavolo
                                            </>
                                        )}
                                    </button>

                                    {/* Security & Trust Icons */}
                                    <div className="flex flex-col sm:flex-row items-center justify-center gap-4 mt-6 pt-4 border-t border-gold/20 text-xs text-gray-400 font-medium">
                                        <div className="flex items-center gap-2">
                                            <ShieldCheck size={16} className="text-green-400" />
                                            <span>Pagamento end-to-end crittografato</span>
                                        </div>
                                        <div className="hidden sm:block w-1 h-1 rounded-full bg-white/20"></div>
                                        <div className="flex items-center gap-3">
                                            <span>Powered by</span>
                                            <div className="font-bold tracking-tighter text-white opacity-80 flex items-center gap-1"><CreditCard size={14}/> Stripe</div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* Right: Order Summary Sidebar */}
                    <div className="lg:col-span-4 space-y-6">
                        <div className="bg-bg-dark/50 border border-white/10 rounded-2xl p-6 sticky top-32">
                            <h2 className="text-lg font-bold text-white mb-6 font-mohave tracking-wide uppercase border-b border-white/10 pb-4">Riepilogo Ordine</h2>

                            <div className="space-y-5 text-sm">
                                <div className="space-y-1">
                                    <p className="text-xs uppercase tracking-widest text-gray-500 font-bold uppercase">L&apos;Esperienza</p>
                                    <p className="text-white text-base font-medium">{event.title}</p>
                                    {selectedDate && <p className="text-gold">{selectedDate.toLocaleDateString('it-IT', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}</p>}
                                </div>

                                <div className="space-y-1">
                                    <p className="text-xs uppercase tracking-widest text-gray-500 font-bold uppercase">Ospiti & Location</p>
                                    <p className="text-white font-medium">{quantity} Posti al Tavolo</p>
                                    <p className="text-gray-400">{event.location}</p>
                                </div>

                                {step > 1 && guest.name && (
                                    <div className="space-y-1 border-t border-white/5 pt-4 mt-4 animate-[fadeIn_0.5s_ease-out]">
                                        <p className="text-xs uppercase tracking-widest text-gray-500 font-bold uppercase">Intestatario</p>
                                        <p className="text-white font-medium">{guest.name} {guest.surname}</p>
                                        <p className="text-gray-400 break-all">{guest.email}</p>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>

                </div>
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import Image from "next/image";
import { ImmersiveHeader } from "@/components/layout/ImmersiveHeader";
import { PremiumButton } from "@/components/ui/PremiumButton";
import { Send, Mail, MapPin, Instagram, Sparkles, ChevronDown, Phone } from "lucide-react";
import { Turnstile } from "@marsidev/react-turnstile";
import { submitContact } from "@/app/actions/contact";
import { useGSAP } from "@/hooks/useGSAP";
import { animateFade } from "@/lib/gsapAnimations";
import { CONTACT_EMAIL, CONTACT_PHONE, SOCIAL_LINKS } from "@/lib/constants";

export default function ContactPage() {
    const [sent, setSent] = useState(false);
    const [status, setStatus] = useState<"idle" | "loading" | "error" | "success">("idle");
    const [msg, setMsg] = useState("");
    const [turnstileToken, setTurnstileToken] = useState("");

    useGSAP(() => {
        animateFade("#contact-info", "up", 0.1);
        animateFade("#contact-form-container", "up", 0.05);
    });

    // Fallback environment var check, will only render Turnstile if public key is available
    const siteKey = process.env.NEXT_PUBLIC_TURNSTILE_SITE_KEY;

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setStatus("loading");
        setMsg("");

        const formData = new FormData(e.currentTarget);
        if (turnstileToken) formData.append("cf-turnstile-response", turnstileToken);

        try {
            const res = await submitContact(formData);
            if (res?.error) {
                setStatus("error");
                setMsg(res.error);
            } else {
                setStatus("success");
                setSent(true);
            }
        } catch {
            setStatus("error");
            setMsg("Errore di rete improvviso. Ritenta più tardi.");
        }
    };

    return (
        <div className="min-h-screen pb-24">
            <ImmersiveHeader
                id="contact-hero"
                title="CONTATTACI"
                highlight=""
                subtitle=""
                mediaUrl=""
            />

            <div className="max-w-7xl mx-auto px-4 sm:px-6 py-12 md:-mt-24 relative z-10 grid grid-cols-1 md:grid-cols-2 gap-12 md:gap-24 items-start">

                {/* Info Column (Top on mobile) */}
                <div id="contact-info" className="space-y-10 md:space-y-12">
                    <div className="gsap-fade">
                        <span className="font-rock-salt text-rama-accent transform -rotate-2 text-xl block mb-4">
                            <Sparkles size={14} className="inline mr-2" /> L&apos;Agenzia
                        </span>
                        <h2 className="font-mohave font-bold leading-[0.85] tracking-tighter uppercase text-white flex flex-col text-4xl md:text-7xl">
                            <span className="text-white">Il tuo evento</span>
                            <span className="text-rama-accent">inizia da qui.</span>
                        </h2>
                        <p className="text-rama-muted font-outfit text-base md:text-lg leading-relaxed mt-6">
                            Scrivici. Rispondiamo entro un'ora. Il tuo tavolo è già pronto — manca solo la data.
                        </p>
                    </div>

                    <div className="grid grid-cols-1 gap-4">
                        {[
                            { label: "Email", value: CONTACT_EMAIL, icon: Mail, href: `mailto:${CONTACT_EMAIL}` },
                            { label: "Telefono", value: CONTACT_PHONE, icon: Phone, href: `tel:${CONTACT_PHONE.replace(/\s+/g, '')}` },
                            { label: "Social", value: "@blackbullslab", icon: Instagram, href: SOCIAL_LINKS.instagram },
                            { label: "Indirizzo", value: "Torino, Italia", icon: MapPin },
                        ].map((info) => (
                            <div key={info.label} className="gsap-fade">
                                {info.href ? (
                                    <a 
                                        href={info.href} 
                                        target={info.href.startsWith('http') ? "_blank" : undefined}
                                        rel={info.href.startsWith('http') ? "noopener noreferrer" : undefined}
                                        className="flex items-center gap-4 p-5 border border-white/5 bg-white/5 rounded-xl hover:border-rama-accent/40 hover:bg-white/[0.08] transition-all group"
                                    >
                                        <div className="w-10 h-10 rounded-full bg-rama-accent/10 flex items-center justify-center text-rama-accent group-hover:bg-rama-accent group-hover:text-black transition-colors">
                                            <info.icon size={20} />
                                        </div>
                                        <div>
                                            <span className="block font-outfit text-[10px] text-rama-muted tracking-widest uppercase mb-0.5">{info.label}</span>
                                            <span className="text-white font-medium text-base md:text-lg">{info.value}</span>
                                        </div>
                                    </a>
                                ) : (
                                    <div className="flex items-center gap-4 p-5 border border-white/5 bg-white/5 rounded-xl transition-all">
                                        <div className="w-10 h-10 rounded-full bg-rama-accent/10 flex items-center justify-center text-rama-accent">
                                            <info.icon size={20} />
                                        </div>
                                        <div>
                                            <span className="block font-outfit text-[10px] text-rama-muted tracking-widest uppercase mb-0.5">{info.label}</span>
                                            <span className="text-white font-medium text-base md:text-lg">{info.value}</span>
                                        </div>
                                    </div>
                                )}
                            </div>
                        ))}

                        {/* WhatsApp Specific Button for Mobile */}
                        <div className="gsap-fade pt-2">
                            <a 
                                href={`https://wa.me/${CONTACT_PHONE.replace(/[^0-9]/g, '')}`}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="flex items-center justify-center gap-3 w-full bg-[#25D366] text-white font-mohave font-bold uppercase tracking-widest p-5 rounded-xl hover:bg-[#20ba5a] transition-colors shadow-lg shadow-green-500/10"
                            >
                                <Phone size={20} />
                                Scrivici su WhatsApp — rispondiamo subito
                            </a>
                        </div>
                    </div>

                    <div className="gsap-fade w-full aspect-[16/9] md:aspect-[4/3] rounded-2xl overflow-hidden relative group hidden md:block">
                        <Image
                            src="/images/brand/bg-venue-crowd.png"
                            alt="Atmosfera Black Bulls Lab"
                            fill
                            className="object-cover group-hover:scale-105 transition-transform duration-1000"
                            sizes="(max-width: 1024px) 100vw, 50vw"
                        />
                        <div className="absolute inset-0 bg-black/20" />
                    </div>
                </div>

                {/* Form Column (Bottom on mobile) */}
                <div
                    id="contact-form-container"
                    className="border border-white/10 bg-[#0c0c0c]/80 backdrop-blur-xl relative rounded-2xl shadow-2xl overflow-hidden"
                >
                    {sent ? (
                        <div className="p-10 md:p-20 text-center py-24 md:py-32">
                            <div className="w-20 h-20 rounded-full bg-rama-accent/10 border border-rama-accent/30 mx-auto flex items-center justify-center mb-8">
                                <Send size={32} className="text-rama-accent" />
                            </div>
                            <h3 className="font-mohave text-3xl md:text-4xl font-bold text-white uppercase mb-4">Messaggio<br /><span className="text-rama-accent">Inviato</span></h3>
                            <p className="text-rama-muted font-outfit text-base md:text-lg">
                                Ti risponderemo entro 24/48 ore. Grazie!
                            </p>
                        </div>
                    ) : (
                        <form onSubmit={handleSubmit} className="p-8 md:p-12 space-y-8">
                            <div className="space-y-2">
                                <h3 className="font-mohave text-2xl md:text-3xl font-bold text-white uppercase">Siamo qui — <span className="text-rama-accent">scrivici</span></h3>
                                <p className="text-rama-muted font-outfit text-sm">Compila il modulo sotto e ti ricontatteremo.</p>
                            </div>

                            {msg && status === "error" && (
                                <div className="bg-red-500/10 border border-red-500/30 p-4 rounded-xl text-red-400 text-sm font-outfit">
                                    {msg}
                                </div>
                            )}

                            <div className="space-y-6">
                                {/* Name */}
                                <div className="gsap-fade space-y-2">
                                    <label htmlFor="name" className="block font-outfit text-xs text-rama-accent/80 tracking-widest uppercase font-bold">Nome e Cognome</label>
                                    <input
                                        id="name"
                                        type="text"
                                        name="name"
                                        required
                                        placeholder="Il tuo nome"
                                        className="w-full bg-white/5 border border-white/10 p-4 text-white rounded-xl focus:border-rama-accent/50 focus:outline-none focus:ring-1 focus:ring-rama-accent/20 transition-all font-outfit"
                                    />
                                </div>

                                {/* Email */}
                                <div className="gsap-fade space-y-2">
                                    <label htmlFor="email" className="block font-outfit text-xs text-rama-accent/80 tracking-widest uppercase font-bold">Email</label>
                                    <input
                                        id="email"
                                        type="email"
                                        name="email"
                                        required
                                        placeholder="la.tua@email.com"
                                        className="w-full bg-white/5 border border-white/10 p-4 text-white rounded-xl focus:border-rama-accent/50 focus:outline-none focus:ring-1 focus:ring-rama-accent/20 transition-all font-outfit"
                                    />
                                </div>

                                {/* Subject */}
                                <div className="gsap-fade space-y-2">
                                    <label htmlFor="subject" className="block font-outfit text-xs text-rama-accent/80 tracking-widest uppercase font-bold">Motivo della Richiesta</label>
                                    <select
                                        id="subject"
                                        name="subject"
                                        required
                                        className="w-full bg-white/5 border border-white/10 p-4 text-white rounded-xl focus:border-rama-accent/50 focus:outline-none cursor-pointer font-outfit appearance-none"
                                    >
                                        <option value="" className="bg-[#0c0c0c] text-white/50">Seleziona un motivo...</option>
                                        <option value="event" className="bg-[#0c0c0c]">Informazioni Eventi</option>
                                        <option value="booking" className="bg-[#0c0c0c]">Prenotazione Dinner Show</option>
                                        <option value="corporate" className="bg-[#0c0c0c]">Collaborazione Corporate</option>
                                        <option value="talent" className="bg-[#0c0c0c]">Candidatura Artista</option>
                                        <option value="other" className="bg-[#0c0c0c]">Altro</option>
                                    </select>
                                </div>

                                {/* Message */}
                                <div className="gsap-fade space-y-2">
                                    <label htmlFor="message" className="block font-outfit text-xs text-rama-accent/80 tracking-widest uppercase font-bold">Messaggio</label>
                                    <textarea
                                        id="message"
                                        name="message"
                                        required
                                        minLength={10}
                                        rows={4}
                                        placeholder="Come possiamo aiutarti?"
                                        className="w-full bg-white/5 border border-white/10 p-4 text-white rounded-xl focus:border-rama-accent/50 focus:outline-none focus:ring-1 focus:ring-rama-accent/20 transition-all font-outfit min-h-[120px] resize-none"
                                    />
                                </div>
                            </div>

                            {siteKey && (
                                <div className="flex justify-center">
                                    <Turnstile siteKey={siteKey} onSuccess={setTurnstileToken} options={{ theme: 'dark' }} />
                                </div>
                            )}

                            <div className="gsap-fade pt-4">
                                <button
                                    type="submit"
                                    disabled={status === 'loading'}
                                    className={`w-full bg-rama-accent text-black font-mohave font-bold uppercase tracking-widest p-5 rounded-xl hover:bg-white transition-all transform active:scale-[0.98] shadow-xl shadow-rama-accent/10 ${status === 'loading' ? 'opacity-50' : ''}`}
                                >
                                    {status === "loading" ? "Invio in corso…" : "Invia Messaggio"}
                                </button>
                            </div>
                        </form>
                    )}
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useRef } from "react";
import { Ticket, Users, CreditCard, Lock, CheckCircle, Minus, Plus, Calendar, MapPin } from "lucide-react";
import { useGSAP } from "@/hooks/useGSAP";
import { gsap } from "gsap";

interface EventBookingSectionProps {
    eventId: string;
    slug: string;
    title: string;
    date: string;
    location: string;
    price?: number;
}

export function EventBookingSection({ eventId, slug, title, date, location, price }: EventBookingSectionProps) {
    const [quantity, setQuantity] = useState(2);
    const [loading, setLoading] = useState(false);
    const [booked, setBooked] = useState(false);
    const [form, setForm] = useState({ nome: "", cognome: "", email: "", telefono: "", note: "" });
    const containerRef = useRef<HTMLDivElement>(null);

    const ticketPrice = price || 0;
    const total = ticketPrice * quantity;

    useGSAP(() => {
        if (booked) {
            gsap.fromTo("#booked-success", 
                { opacity: 0, scale: 0.95 },
                { opacity: 1, scale: 1, duration: 0.5, ease: "back.out(1.7)" }
            );
        } else {
            gsap.fromTo("#booking-form-content", 
                { opacity: 0, y: 20 },
                { opacity: 1, y: 0, duration: 0.6, ease: "power2.out" }
            );
        }
    }, { dependencies: [booked], scope: containerRef });

    const handlePayment = async () => {
        setLoading(true);
        try {
            const response = await fetch("/api/checkout", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    eventId,
                    eventTitle: title,
                    quantity,
                    selectedDate: date,
                    guest: {
                        name: form.nome,
                        surname: form.cognome,
                        email: form.email,
                        phone: form.telefono
                    },
                    premium: {
                        allergies: form.note,
                        occasion: "Nessuna specifica"
                    },
                    unitAmount: ticketPrice * 100 // Convert to cents
                })
            });
            const data = await response.json();
            if (data.url) {
                window.location.href = data.url;
            } else {
                throw new Error(data.error || "Errore sconosciuto");
            }
        } catch (error) {
            console.error("Errore di pagamento:", error);
            alert("Si è verificato un errore durante la connessione al sistema di pagamento.");
            setLoading(false);
        }
    };

    if (ticketPrice === 0) return null;

    return (
        <section ref={containerRef} className="py-16 px-6 max-w-4xl mx-auto">
            <div className="flex items-center gap-3 mb-8">
                <div className="w-1 h-6 bg-gold/50" />
                <h3 className="text-2xl font-bold text-white tracking-tight">Prenota il Tuo Posto</h3>
            </div>

            {booked ? (
                <div
                    id="booked-success"
                    className="border border-gold/20 bg-bg-card/50 p-12 text-center opacity-0"
                >
                    <CheckCircle size={48} className="text-gold mx-auto mb-4" />
                    <h3 className="text-2xl font-bold text-white mb-2">Prenotazione Confermata!</h3>
                    <p className="text-gray-400 mb-1">
                        {quantity} bigliett{quantity === 1 ? "o" : "i"} per <span className="text-gold">{title}</span>
                    </p>
                    <p className="text-gray-500 text-sm">
                        Riceverai una conferma via email a <span className="text-gold/70">{form.email}</span>
                    </p>
                </div>
            ) : (
                <div
                    id="booking-form-content"
                    className="grid grid-cols-1 md:grid-cols-3 gap-6 opacity-0"
                >
                    {/* Left: Ticket selection + Details */}
                    <div className="md:col-span-2 space-y-5">
                        {/* Ticket selection */}
                        <div className="border border-border bg-bg-card/40 p-6">
                            <div className="flex items-center gap-2 mb-5">
                                <Ticket size={16} className="text-gold/50" />
                                <span className="text-xs text-gold/50 uppercase tracking-widest font-medium">Biglietti</span>
                            </div>

                            <div className="flex items-center justify-between">
                                <div>
                                    <p className="text-white font-medium">Esperienza Completa</p>
                                    <p className="text-gold text-lg font-bold">€ {ticketPrice},00 <span className="text-gray-500 text-xs font-normal">/ persona</span></p>
                                </div>
                                <div className="flex items-center gap-3 border border-border bg-bg-dark p-1.5">
                                    <button
                                        onClick={() => setQuantity(Math.max(1, quantity - 1))}
                                        className="w-8 h-8 flex items-center justify-center text-gray-400 hover:text-gold hover:bg-gold/5 transition-all"
                                    >
                                        <Minus size={14} />
                                    </button>
                                    <span className="text-white font-bold w-6 text-center">{quantity}</span>
                                    <button
                                        onClick={() => setQuantity(Math.min(10, quantity + 1))}
                                        className="w-8 h-8 flex items-center justify-center text-gray-400 hover:text-gold hover:bg-gold/5 transition-all"
                                    >
                                        <Plus size={14} />
                                    </button>
                                </div>
                            </div>
                        </div>

                        {/* Personal details */}
                        <div className="border border-border bg-bg-card/40 p-6">
                            <div className="flex items-center gap-2 mb-5">
                                <Users size={16} className="text-gold/50" />
                                <span className="text-xs text-gold/50 uppercase tracking-widest font-medium">I Tuoi Dati</span>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                <input
                                    type="text"
                                    placeholder="Nome"
                                    value={form.nome}
                                    onChange={(e) => setForm({ ...form, nome: e.target.value })}
                                    className="bg-bg-dark border border-border px-4 py-3 text-white text-sm placeholder:text-gray-600 focus:outline-none focus:border-gold/30 transition-colors"
                                />
                                <input
                                    type="text"
                                    placeholder="Cognome"
                                    value={form.cognome}
                                    onChange={(e) => setForm({ ...form, cognome: e.target.value })}
                                    className="bg-bg-dark border border-border px-4 py-3 text-white text-sm placeholder:text-gray-600 focus:outline-none focus:border-gold/30 transition-colors"
                                />
                                <input
                                    type="email"
                                    placeholder="Email"
                                    value={form.email}
                                    onChange={(e) => setForm({ ...form, email: e.target.value })}
                                    className="bg-bg-dark border border-border px-4 py-3 text-white text-sm placeholder:text-gray-600 focus:outline-none focus:border-gold/30 transition-colors"
                                />
                                <input
                                    type="tel"
                                    placeholder="Telefono"
                                    value={form.telefono}
                                    onChange={(e) => setForm({ ...form, telefono: e.target.value })}
                                    className="bg-bg-dark border border-border px-4 py-3 text-white text-sm placeholder:text-gray-600 focus:outline-none focus:border-gold/30 transition-colors"
                                />
                            </div>
                            <textarea
                                placeholder="Allergie o note per lo chef (opzionale)"
                                value={form.note}
                                onChange={(e) => setForm({ ...form, note: e.target.value })}
                                rows={2}
                                className="w-full mt-3 bg-bg-dark border border-border px-4 py-3 text-white text-sm placeholder:text-gray-600 focus:outline-none focus:border-gold/30 transition-colors resize-none"
                            />
                        </div>
                    </div>

                    {/* Right: Order summary */}
                    <div className="space-y-5">
                        <div className="border border-border bg-bg-card/40 p-6 sticky top-28">
                            <span className="text-xs text-gold/50 uppercase tracking-widest font-medium block mb-5">Riepilogo</span>

                            <div className="space-y-3 text-sm mb-6">
                                <div className="flex items-start gap-2">
                                    <Calendar size={14} className="text-gold/40 mt-0.5 shrink-0" />
                                    <span className="text-gray-300">{date}</span>
                                </div>
                                <div className="flex items-start gap-2">
                                    <MapPin size={14} className="text-gold/40 mt-0.5 shrink-0" />
                                    <span className="text-gray-300">{location}</span>
                                </div>
                                <div className="flex items-start gap-2">
                                    <Ticket size={14} className="text-gold/40 mt-0.5 shrink-0" />
                                    <span className="text-gray-300">{quantity} bigliett{quantity === 1 ? "o" : "i"}</span>
                                </div>
                            </div>

                            <div className="border-t border-border pt-4 mb-6">
                                <div className="flex justify-between items-center">
                                    <span className="text-gray-400 text-sm">Totale</span>
                                    <span className="text-3xl font-bold text-white">€ {total},00</span>
                                </div>
                            </div>

                            <button
                                onClick={handlePayment}
                                disabled={loading || !form.nome || !form.email}
                                className="w-full py-4 bg-gradient-to-r from-gold-dim via-gold to-gold-dim text-bg-dark font-bold uppercase tracking-widest text-sm
