                            >
                                {loading ? (
                                    "Elaborazione..."
                                ) : (
                                    <>
                                        <Lock size={16} /> Paga Ora
                                    </>
                                )}
                            </button>

                            <div className="flex items-center justify-center gap-2 mt-4 text-[10px] text-gray-500">
                                <CreditCard size={10} />
                                <span>Pagamento sicuro · Stripe</span>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </section>
