                                        type="range" 
                                        min="10" 
                                        max="100" 
                                        step="1"
                                        value={numPeople}
                                        onChange={(e) => setNumPeople(parseInt(e.target.value))}
                                        className="w-full h-2 bg-white/10 rounded-lg appearance-none cursor-pointer accent-rama-accent"
                                    />
                                    <div className="flex justify-between text-[10px] font-outfit text-white/30 uppercase tracking-widest">
                                        <span>Min 10</span>
                                        <span>Max 100</span>
                                    </div>
                                </div>
                            </div>

                            <div className="space-y-4">
