                                    onClick={() => setStep(3)}
                                    className="w-full bg-rama-accent text-black font-mohave font-bold uppercase tracking-widest text-sm px-8 py-4 rounded-xl hover:bg-white transition-all duration-300 shadow-[0_4px_20px_rgba(200,164,78,0.2)]"
                                >
                                    Scopri i Format →
                                </button>
                                <button onClick={() => { setStep(1); setSelectedOccasion(null); }} className="text-white/40 hover:text-white font-outfit text-sm underline underline-offset-4 transition-colors mx-auto block">
                                    ← Torna all&apos;occasione
                                </button>
                            </div>
                        </div>
                    )}

                    {/* Step 3 — Results */}
                    {step === 3 && (
                        <div key="step3">
