                                    const d = formatDetails[fmt];
                                    return (
                                        <div key={fmt} className="flex flex-col gap-4 p-5 sm:p-6 rounded-xl border border-white/10 bg-white/[0.03] hover:border-rama-accent/30 transition-all duration-300">
